4	bool ConvertKeyEvent(UINT vkey,
5	                     KeyInfo kinfo,
6	                     const LPBYTE keyState,
7	                     weasel::KeyEvent& result) {
8	  const BYTE KEY_DOWN = 0x80;
9	  const BYTE TOGGLED = 0x01;
10	  ibus::Keycode TranslateKeycode(UINT vkey, KeyInfo kinfo);
11	
12	  // set mask
13	  result.mask = ibus::NULL_MASK;
14	
15	  if ((keyState[VK_SHIFT] & KEY_DOWN) != 0)
16	    result.mask |= ibus::SHIFT_MASK;
17	
18	  if ((keyState[VK_CAPITAL] & TOGGLED) != 0)
19	    result.mask |= ibus::LOCK_MASK;
20	
21	  if ((keyState[VK_CONTROL] & KEY_DOWN) != 0)
22	    result.mask |= ibus::CONTROL_MASK;
23	
24	  if ((keyState[VK_MENU] & KEY_DOWN) != 0)
25	    result.mask |= ibus::ALT_MASK;
26	
27	  if (kinfo.isKeyUp)
28	    result.mask |= ibus::RELEASE_MASK;
29	
30	  if (vkey == VK_CAPITAL && !kinfo.isKeyUp) {
31	    // NOTE: rime assumes XK_Caps_Lock to be sent before modifier changes,
32	    // while VK_CAPITAL has the modifier changed already.
33	    // so it is necessary to revert LOCK_MASK.
34	    result.mask ^= ibus::LOCK_MASK;
35	  }
36	
37	  // set keycode
38	  ibus::Keycode code = TranslateKeycode(vkey, kinfo);
39	  if (code) {
40	    result.keycode = code;
41	    return true;
42	  }
43	
44	  const int buf_len = 8;
45	  static WCHAR buf[buf_len];
46	  static BYTE table[256];
47	  // 清除Ctrl、Alt鍵狀態，以令ToUnicodeEx()返回字符
48	  memcpy(table, keyState, sizeof(table));
49	  table[VK_CONTROL] = 0;
50	  table[VK_MENU] = 0;
51	  int ret = ToUnicodeEx(vkey, UINT(kinfo), table, buf, buf_len, 0, NULL);
52	  if (ret == 1) {
53	    result.keycode = UINT(buf[0]);
54	    return true;
55	  }
56	
57	  result.keycode = 0;
58	  return false;
59	}
