61	ibus::Keycode TranslateKeycode(UINT vkey, KeyInfo kinfo) {
62	  switch (vkey) {
63	    case VK_BACK:
64	      return ibus::BackSpace;
65	    case VK_TAB:
66	      return ibus::Tab;
67	    case VK_CLEAR:
68	      return ibus::Clear;
69	    case VK_RETURN: {
70	      if (kinfo.isExtended == 1)
71	        return ibus::KP_Enter;
72	      else
73	        return ibus::Return;
74	    }
75	    case VK_SHIFT: {
76	      if (kinfo.scanCode == 0x36)
77	        return ibus::Shift_R;
78	      else
79	        return ibus::Shift_L;
80	    }
81	    case VK_CONTROL: {
82	      if (kinfo.isExtended == 1)
83	        return ibus::Control_R;
84	      else
85	        return ibus::Control_L;
86	    }
87	    case VK_MENU:
88	      return ibus::Alt_L;
89	    case VK_PAUSE:
